<!DOCTYPE html>
<html lang="pt">
<head>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    :root {
      --brand-orange: #FF6B35;
      --brand-orange-dark: #E55A27;
      --brand-orange-light: #FFF0EB;
      --neutral-900: #1A1A1A;
      --neutral-700: #4A4A4A;
      --neutral-400: #9E9E9E;
      --neutral-200: #F0F0F0;
      --neutral-100: #FAFAFA;
      --success: #2ECC71;
      --font-heading: 'Montserrat', sans-serif;
      --font-body: 'Open Sans', sans-serif;
    }
    body { font-family: var(--font-body); background: var(--neutral-100); }
    .navbar { background: white; padding: 0 40px; height: 64px; display: flex; align-items: center; justify-content: space-between; border-bottom: 2px solid var(--brand-orange); }
    .logo { font-family: var(--font-heading); font-size: 24px; font-weight: 800; color: var(--brand-orange); letter-spacing: -0.5px; }
    .search-bar { display: flex; flex: 1; max-width: 500px; margin: 0 32px; }
    .search-bar input { flex: 1; padding: 10px 16px; border: 2px solid var(--neutral-200); border-right: none; border-radius: 8px 0 0 8px; font-size: 14px; }
    .search-bar button { padding: 10px 20px; background: var(--brand-orange); color: white; border: none; border-radius: 0 8px 8px 0; font-weight: 600; cursor: pointer; }
    .btn-cart { position: relative; background: var(--brand-orange); color: white; border: none; padding: 8px 16px; border-radius: 8px; font-weight: 600; font-size: 14px; cursor: pointer; }
    .product-card { background: white; border-radius: 12px; overflow: hidden; transition: transform 0.2s, box-shadow 0.2s; }
    .product-card:hover { transform: translateY(-4px); box-shadow: 0 12px 24px rgba(0,0,0,0.1); }
    .product-img { width: 100%; aspect-ratio: 1; object-fit: cover; background: var(--neutral-200); }
    .product-info { padding: 16px; }
    .product-name { font-family: var(--font-heading); font-size: 15px; font-weight: 600; color: var(--neutral-900); margin-bottom: 4px; }
    .product-price { font-size: 22px; font-weight: 700; color: var(--brand-orange); }
    .product-price-old { font-size: 14px; color: var(--neutral-400); text-decoration: line-through; }
    .discount-badge { background: var(--brand-orange); color: white; font-size: 11px; font-weight: 700; padding: 2px 6px; border-radius: 4px; }
    .btn-add-cart { width: 100%; margin-top: 12px; padding: 10px; background: var(--brand-orange); color: white; border: none; border-radius: 8px; font-weight: 600; font-size: 14px; cursor: pointer; transition: background 0.15s; }
    .btn-add-cart:hover { background: var(--brand-orange-dark); }
    .tag { display: inline-block; padding: 3px 10px; border-radius: 100px; font-size: 12px; background: var(--brand-orange-light); color: var(--brand-orange); font-weight: 500; }
    h1, h2, h3 { font-family: var(--font-heading); }
    h1 { font-size: 32px; font-weight: 800; color: var(--neutral-900); }
    h2 { font-size: 24px; font-weight: 700; color: var(--neutral-900); }
    p { font-size: 14px; line-height: 1.6; color: var(--neutral-700); }
    .section { padding: 48px 40px; }
    .grid-products { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); gap: 24px; }
  </style>
</head>
